package com.cognizant.springmockito;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.http.ResponseEntity;@ExtendWith(MockitoExtension.class) public class UserControllerTest {@Mock UserService userService;@InjectMocks UserController userController;@Test void testGetUser(){when(userService.getUserById(1L)).thenReturn(new User(1L,"Aman"));ResponseEntity<User> response=userController.getUserById(1L);assertEquals(200,response.getStatusCode().value());assertNotNull(response.getBody());assertEquals(1L,response.getBody().getId());assertEquals("Aman",response.getBody().getName());verify(userService).getUserById(1L);}}
